+	// Rig menu binding (prefix + r)
+	rigMenuCmd := "gt rig menu"
+	if townSocket != "" {
+		rigMenuCmd = fmt.Sprintf("GT_TOWN_SOCKET=%s gt rig menu", townSocket)
+	}
